class Solution:
    def furthestBuilding(self, heights, bricks, ladders):
        n = len(heights)
        diffs = [heights[i + 1] - heights[i] for i in range(n - 1)]

        def feasible(k):
            climbs = sorted((d for d in diffs[:k] if d > 0), reverse=True)
            paid_with_bricks = climbs[ladders:]
            return sum(paid_with_bricks) <= bricks

        lo, hi = 0, n - 1
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

